class LightConvBlock(nn.Module):
    """
    轻量卷积块：两个 1×1 卷积 + 可选激活函数（SiLU 或 ReLU）
    """

    def __init__(self, c, act_type='silu'):
        super().__init__()
        self.conv1 = nn.Conv2d(c, c, 1, 1, 0, bias=False)
        self.bn1 = nn.BatchNorm2d(c)
        self.conv2 = nn.Conv2d(c, c, 1, 1, 0, bias=True)
        self.act = self._get_activation(act_type)

    def _get_activation(self, act_type):
        if act_type == 'relu':
            return nn.ReLU()
        elif act_type == 'silu':
            return nn.SiLU()
        else:
            raise ValueError(f"Unsupported activation type: {act_type}")

    def forward(self, x):
        x = self.conv1(x)
        x = self.bn1(x)
        x = self.conv2(x)
        x = self.act(x)
        return x


class LightASFF2(nn.Module):
    def __init__(self, c1, c2=None, level=0, act_type='silu'):
        super().__init__()
        c1_l, c1_h = c1
        self.level = level
        self.inter_dim = [c1_l, c1_h][level]
        compress_c = 8
        if level == 0:
            self.up_h = nn.ConvTranspose2d(c1_h, self.inter_dim, 2, 2)
        else:
            self.down_l = nn.Conv2d(c1_l, self.inter_dim, 2, 2)
        self.w_l = nn.Conv2d(self.inter_dim, compress_c, 1)
        self.w_h = nn.Conv2d(self.inter_dim, compress_c, 1)
        self.w_all = nn.Conv2d(compress_c * 2, 2, 1)
        self.fuse = LightConvBlock(self.inter_dim, act_type=act_type)

    def forward(self, x):
        x_l, x_h = x
        if self.level == 0:
            l = x_l
            h = self.up_h(x_h)
        else:
            l = self.down_l(x_l)
            h = x_h
        wl = self.w_l(l)
        wh = self.w_h(h)
        weights = self.w_all(torch.cat([wl, wh], dim=1))
        weights = F.softmax(weights, dim=1)
        fused = l * weights[:, 0:1] + h * weights[:, 1:2]
        return self.fuse(fused)


class LightASFF3(nn.Module):
    def __init__(self, c1, c2=None, level=0, act_type='silu'):
        super().__init__()
        c1_l, c1_m, c1_h = c1
        self.level = level
        self.inter_dim = [c1_l, c1_m, c1_h][level]
        compress_c = 8
        if level == 0:
            self.up_m = nn.ConvTranspose2d(c1_m, self.inter_dim, 2, 2)
            self.up_h = nn.ConvTranspose2d(c1_h, self.inter_dim, 4, 4)
        elif level == 1:
            self.down_l = nn.Conv2d(c1_l, self.inter_dim, 2, 2)
            self.up_h = nn.ConvTranspose2d(c1_h, self.inter_dim, 2, 2)
        else:
            self.down_l = nn.Conv2d(c1_l, self.inter_dim, 4, 4)
            self.down_m = nn.Conv2d(c1_m, self.inter_dim, 2, 2)
        self.w_l = nn.Conv2d(self.inter_dim, compress_c, 1)
        self.w_m = nn.Conv2d(self.inter_dim, compress_c, 1)
        self.w_h = nn.Conv2d(self.inter_dim, compress_c, 1)
        self.w_all = nn.Conv2d(compress_c * 3, 3, 1)
        self.fuse = LightConvBlock(self.inter_dim, act_type=act_type)

    def forward(self, x):
        x_l, x_m, x_h = x
        if self.level == 0:
            l, m, h = x_l, self.up_m(x_m), self.up_h(x_h)
        elif self.level == 1:
            l, m, h = self.down_l(x_l), x_m, self.up_h(x_h)
        else:
            l, m, h = self.down_l(x_l), self.down_m(x_m), x_h
        wl = self.w_l(l)
        wm = self.w_m(m)
        wh = self.w_h(h)
        weights = self.w_all(torch.cat([wl, wm, wh], dim=1))
        weights = F.softmax(weights, dim=1)
        fused = l * weights[:, 0:1] + m * weights[:, 1:2] + h * weights[:, 2:3]
        return self.fuse(fused)


import torch
import torch.nn as nn
import torch.nn.functional as F


# 深度可分离卷积（Depthwise Separable Convolution）定义
class DepthwiseSeparableConv(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size=3, stride=1, padding=1):
        super(DepthwiseSeparableConv, self).__init__()
        # 深度卷积
        self.depthwise = nn.Conv2d(in_channels, in_channels, kernel_size=kernel_size, stride=stride, padding=padding,
                                   groups=in_channels, bias=False)
        # 点卷积（1x1卷积）
        self.pointwise = nn.Conv2d(in_channels, out_channels, kernel_size=1, stride=1, padding=0, bias=False)
        self.bn = nn.BatchNorm2d(out_channels)  # 批归一化
        self.act = nn.SiLU()  # 激活函数，可以根据需要更改为其他类型

    def forward(self, x):
        x = self.depthwise(x)
        x = self.pointwise(x)
        x = self.bn(x)
        return self.act(x)


# 跨尺度注意力机制（Cross-Scale Attention）定义
class CrossScaleAttention(nn.Module):
    def __init__(self, inp, oup, reduction=32):
        super(CrossScaleAttention, self).__init__()
        # self.pool_h = nn.AdaptiveAvgPool2d((None, 1)) <-- 删除
        # self.pool_w = nn.AdaptiveAvgPool2d((1, None)) <-- 删除
        mip = max(8, inp // reduction)
        self.conv1 = nn.Conv2d(inp, mip, kernel_size=1, stride=1, padding=0)
        self.bn1 = nn.BatchNorm2d(mip)
        self.act = nn.SiLU()
        self.conv_h = nn.Conv2d(mip, oup, kernel_size=1, stride=1, padding=0)
        self.conv_w = nn.Conv2d(mip, oup, kernel_size=1, stride=1, padding=0)

    def forward(self, x):
        identity = x
        n, c, h, w = x.size()
        # x_h = self.pool_h(x) <-- 改为 mean
        x_h = x.mean(3, keepdim=True)

        # x_w = self.pool_w(x).permute(0, 1, 3, 2) <-- 改为 mean
        x_w = x.mean(2, keepdim=True).permute(0, 1, 3, 2)

        y = torch.cat([x_h, x_w], dim=2)
        # ... 后续代码不变 ...
        y = self.conv1(y)
        y = self.bn1(y)
        y = self.act(y)
        x_h, x_w = torch.split(y, [h, w], dim=2)
        x_w = x_w.permute(0, 1, 3, 2)
        a_h = self.conv_h(x_h).sigmoid()
        a_w = self.conv_w(x_w).sigmoid()
        out = identity * a_w * a_h
        return out


import torch.nn.functional as F


class CSA_DW_LightASFF2(nn.Module):
    def __init__(self, c1, c2=None, level=0):
        super().__init__()
        c1_l, c1_h = c1
        self.level = level
        self.inter_dim = [c1_l, c1_h][level]
        compress_c = 8

        if level == 0:
            self.up_h = nn.ConvTranspose2d(c1_h, self.inter_dim, 2, 2)
        else:
            self.down_l = nn.Conv2d(c1_l, self.inter_dim, 2, 2)

        # 深度可分离卷积
        self.weight_level_0 = DepthwiseSeparableConv(self.inter_dim, compress_c, kernel_size=1)
        self.weight_level_1 = DepthwiseSeparableConv(self.inter_dim, compress_c, kernel_size=1)

        self.weights_levels = nn.Conv2d(compress_c * 2, 2, kernel_size=1, stride=1, padding=0)
        self.coord_att = CoordAtt(self.inter_dim, self.inter_dim)  # Coordination Attention

        self.fuse = LightConvBlock(self.inter_dim)

    def forward(self, x):
        x_l, x_h = x
        if self.level == 0:
            l = x_l
            h = self.up_h(x_h)
        else:
            l = self.down_l(x_l)
            h = x_h

        wl = self.weight_level_0(l)
        wh = self.weight_level_1(h)
        levels_weight_v = torch.cat((wl, wh), 1)
        weights = self.weights_levels(levels_weight_v)
        weights = F.softmax(weights, dim=1)

        # 如果 l 和 h 的尺寸不匹配，调整 weights 的尺寸
        if l.size(2) != weights.size(2) or l.size(3) != weights.size(3):
            weights = F.interpolate(weights, size=l.size()[2:], mode='bilinear', align_corners=False)

        fused_out_reduced = l * weights[:, 0:1] + h * weights[:, 1:2]
        fused_out_reduced = self.fuse(fused_out_reduced)

        # Apply CA attention mechanism
        fused_out_reduced = self.coord_att(fused_out_reduced)

        return fused_out_reduced


class CSA_DW_LightASFF3(nn.Module):
    """ASFF3 module for YOLO AFPN head"""

    def __init__(self, c1, c2, level=0):
        super().__init__()
        c1_l, c1_m, c1_h = c1[0], c1[1], c1[2]
        self.level = level
        self.dim = c1_l, c1_m, c1_h
        self.inter_dim = self.dim[self.level]
        compress_c = 8

        if level == 0:
            self.stride_level_1 = Upsample(c1_m, self.inter_dim)
            self.stride_level_2 = Upsample(c1_h, self.inter_dim, scale_factor=4)

        if level == 1:
            self.stride_level_0 = Conv(c1_l, self.inter_dim, 2, 2, 0)  # downsample 2x
            self.stride_level_2 = Upsample(c1_h, self.inter_dim)

        if level == 2:
            self.stride_level_0 = Conv(c1_l, self.inter_dim, 4, 4, 0)  # downsample 4x
            self.stride_level_1 = Conv(c1_m, self.inter_dim, 2, 2, 0)  # downsample 2x

        self.weight_level_0 = Conv(self.inter_dim, compress_c, 1, 1)
        self.weight_level_1 = Conv(self.inter_dim, compress_c, 1, 1)
        self.weight_level_2 = Conv(self.inter_dim, compress_c, 1, 1)

        self.weights_levels = nn.Conv2d(compress_c * 3, 3, kernel_size=1, stride=1, padding=0)
        self.conv = Conv(self.inter_dim, self.inter_dim, 3, 1)

    def forward(self, x):
        x_level_0, x_level_1, x_level_2 = x[0], x[1], x[2]

        if self.level == 0:
            level_0_resized = x_level_0
            level_1_resized = self.stride_level_1(x_level_1)
            level_2_resized = self.stride_level_2(x_level_2)

        elif self.level == 1:
            level_0_resized = self.stride_level_0(x_level_0)
            level_1_resized = x_level_1
            level_2_resized = self.stride_level_2(x_level_2)

        elif self.level == 2:
            level_0_resized = self.stride_level_0(x_level_0)
            level_1_resized = self.stride_level_1(x_level_1)
            level_2_resized = x_level_2

        # 为每个尺度的特征图计算加权系数
        level_0_weight_v = self.weight_level_0(level_0_resized)
        level_1_weight_v = self.weight_level_1(level_1_resized)
        level_2_weight_v = self.weight_level_2(level_2_resized)

        # 调整权重的尺寸以确保与对应的特征图尺寸一致
        if level_0_weight_v.size(2) != level_0_resized.size(2) or level_0_weight_v.size(3) != level_0_resized.size(3):
            level_0_weight_v = F.interpolate(level_0_weight_v, size=level_0_resized.size()[2:], mode='bilinear',
                                             align_corners=False)

        if level_1_weight_v.size(2) != level_1_resized.size(2) or level_1_weight_v.size(3) != level_1_resized.size(3):
            level_1_weight_v = F.interpolate(level_1_weight_v, size=level_1_resized.size()[2:], mode='bilinear',
                                             align_corners=False)

        if level_2_weight_v.size(2) != level_2_resized.size(2) or level_2_weight_v.size(3) != level_2_resized.size(3):
            level_2_weight_v = F.interpolate(level_2_weight_v, size=level_2_resized.size()[2:], mode='bilinear',
                                             align_corners=False)

        levels_weight_v = torch.cat((level_0_weight_v, level_1_weight_v, level_2_weight_v), 1)
        w = self.weights_levels(levels_weight_v)
        w = F.softmax(w, dim=1)

        # 跨尺度加权融合
        fused_out_reduced = level_0_resized * w[:, :1] + level_1_resized * w[:, 1:2] + level_2_resized * w[:, 2:]
        return self.conv(fused_out_reduced)



